var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"그대는 늘 내게 안식을 권하는구나.","JPN":"そなたはいつも我に安息を勧めてくるな。","ENG":"You are suggesting I rest yet again.","TWN":"你總是勸我要進入安息。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"아직도 모르겠는가. 내게는 안식을 누릴 권리도, 감히 생각에 담을 자격도 없다는 것을.","JPN":"いまだにわからぬか。我には安息を享受する権利も、それを望む資格もないということを。","ENG":"Do you still not realize? I possess no right to rest, nor to even desire for such.","TWN":"難道你不知道，我根本沒條件進入安息，甚至連想的資格都沒有。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"영원한 후회와 속죄만이 내게 남은 유일한 길일진데……. 그대는 어째서…….","JPN":"永遠の後悔と償いだけが我に残された唯一の道であるだろうに……そなたはなにゆえ……","ENG":"The only path allowed for one such as I, is eternal regret and atonement... So why...","TWN":"我將來的路只剩下悔恨與贖罪……可是你為什麼……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"……그렇군.","JPN":"……そうか。","ENG":"...I see.","TWN":"……原來如此。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"그 누구보다 나의 마음을 잘 아는 이가 바로 그대겠지.","JPN":"誰よりも我のこの心を理解しているのがそなたであろう。","ENG":"You must be able to understand me better than any other could.","TWN":"你比任何人都明白我的心情呢。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"그대도……. 수많은 실패와 좌절을 겪고 고독한 번뇌를 홀로 씹어 삼키며 이 세월을 버텨왔던가.","JPN":"そなたも……幾度となく失敗や挫折を経験し、孤独な煩悩をただ一人で耐え忍び、今日この日まで来ているのだから。","ENG":"You have... Despaired in the face of countless failures, and endured lonely agony all this time. All by yourself.","TWN":"你也和我一樣……在漫長的歲月中，經歷過無數的失敗與挫折，有苦難言嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"그러니 묻겠다.","JPN":"ゆえに問おう。","ENG":"So I shall ask.","TWN":"那我問你。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"그대는 정말 나의 안식이 옳다고 보는가.","JPN":"そなたは本当に我の安息が正しいと思うか。","ENG":"Do you truly believe that I am deserved of rest?","TWN":"你真的認為我的安息是正確的嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"아니면…… 혹여 나를 통해 그대를 투영하고 있는 것은 아니던가.","JPN":"それとも……もしや我にそなた自身を投影しているのではないか。","ENG":"Or perhaps... Do you see a reflection of yourself in me?","TWN":"還是……你只是在我身上看到你的影子？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"어느 쪽이든 나를 옥죈 무거운 책임은 모두 져야 함이 당연하다.","JPN":"どちらにせよ我を締め付けるこの重い責任は全うせねばなるまい。","ENG":"Whichever the case, this heavy burden of responsibility of mine is solely for me to uphold.","TWN":"無論答案是哪一個，自然是必須承擔束縛我的沉重責任。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"하지만…… 이 세상은 망령에 불과한 나와는 달리 안식에 들어야 마땅할지니.","JPN":"しかし……この世は、亡霊にすぎない我とは違い、安息に入るべきだ。","ENG":"However... This world deserves rest. Unlike a foul wraith like I.","TWN":"不過……這個世界和流浪的我不同，這個世界需要進入安息。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"그대와 함께 싸운다면, 이제는 내가 그토록 바라왔던 종국의 결말에 닿을 수 있으리란 생각이 드는구나.","JPN":"そなたとともに戦えば、我が望んでやまない終局の結末にたどり着けるであろうと思える。","ENG":"Fighting alongside you... Leads me to believe that I may be able to find the end of the end that I have long awaited.","TWN":"若是與你一起並肩作戰，似乎就能夠達到我至今所期盼的終點。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"실로 오랜만에 들려오는…… 희망의 소리로다.","JPN":"実に久しく聞こえてくる……希望の音だ。","ENG":"The first sounds of hope I am hearing... After an eternity of silence.","TWN":"這算是久違的……好消息。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};